### **Typical Usage Pattern**

```csharp
// 1. Create base chat client (from OpenAI, Anthropic, etc.)
var openAiClient = new OpenAIClient(apiKey);
var chatClient = openAiClient.AsChatClient("gpt-4o");

// 2. Build pipeline with function invocation
var tools = new[]
{
    AIFunctionFactory.Create(
        (string query) => ResearchDatabase.Search(query),
        "search_research",
        "Search the research database"),

    AIFunctionFactory.Create(
        (string url) => WebScraper.FetchPage(url),
        "fetch_url", 
        "Fetch content from URL")
};

var builder = new ChatClientBuilder(chatClient);
builder.UseFunctionInvocation(loggerFactory: null);
var pipelineClient = builder.Build();

// 3. Create agent
var agent = new ChatClientAgent(
    chatClient: pipelineClient,
    instructions: "You are a research assistant. Use tools to find and synthesize information.",
    name: "researcher",
    description: "Performs web research",
    tools: null);  // Tools passed via ChatOptions instead

// 4. Run agent
var session = new AgentSession();
var response = await agent.RunAsync(
    "Research the latest advances in LLM agents",
    session,
    new ChatClientAgentRunOptions(),
    CancellationToken.None);

// 5. Process response
foreach (var message in response.Messages)
{
    foreach (var content in message.Content)
    {
        if (content is TextContent text)
            Console.WriteLine(text.Text);
    }
}
