                     """),
                 new(ChatRole.User,
                     $"Research this topic thoroughly and provide a detailed summary: {topic}"),
             ],
             new ChatOptions { Tools = tools });

         Console.WriteLine("\n── Summary ─────────────────────────────────────────\n");

         // Extract final assistant text from the response
         var summary = string.Join("\n", response.Messages
             .Where(m => m.Role == ChatRole.Assistant)
             .Select(m => m.Text)
             .Where(t => !string.IsNullOrEmpty(t)));

         Console.WriteLine(summary);
         Console.WriteLine("\n────────────────────────────────────────────────────");
         Console.WriteLine($"📊 {notes.Count} note(s) taken during research.\n");
     }
     catch (Exception ex)
     {
         Console.WriteLine($"\n❌ Error: {ex.Message}\n");
     }
 }

 // ── Tool implementations ───────────────────────────────────────

 async Task<string> SearchWebAsync(
     [Description("The search query")] string query)
 {
     Console.WriteLine($"  🌐 Searching: \"{query}\"");

     try
     {
         var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
         using var request = new HttpRequestMessage(HttpMethod.Get, url);
         request.Headers.UserAgent.ParseAdd("Mozilla/5.0 (compatible; ResearchAgent/1.0)");

         using var httpResponse = await http.SendAsync(request);
         httpResponse.EnsureSuccessStatusCode();
         var html = await httpResponse.Content.ReadAsStringAsync();

         var results = ParseSearchResults(html);

         if (results.Count == 0)
             return "No results found. Try rephrasing the query.";

         var sb = new StringBuilder();
         var count = Math.Min(results.Count, 5);
         sb.AppendLine($"Search results for \"{query}\":\n");
         for (var i = 0; i < count; i++)
         {
             sb.AppendLine($"  {i + 1}. {results[i].Title}");
             if (!string.IsNullOrWhiteSpace(results[i].Snippet))
                 sb.AppendLine($"     {results[i].Snippet}");
             sb.AppendLine();
         }

         Console.WriteLine($"  ✅ Found {count} result(s)");
         return sb.ToString();
     }
     catch (Exception ex)
     {
         return $"Search failed: {ex.Message}";
     }
 }

 string TakeNote([Description("The note content to save")] string note)
 {
     notes.Add(note);
     Console.WriteLine($"  📝 Note #{notes.Count} saved");
     return $"Note #{notes.Count} saved successfully.";
 }

 string GetNotes()
 {
     if (notes.Count == 0)
         return "No notes have been saved yet.";

     Console.WriteLine($"  📋 Reviewing {notes.Count} note(s)");

     var sb = new StringBuilder();
     sb.AppendLine($"All research notes ({notes.Count}):\n");
     for (var i = 0; i < notes.Count; i++)
         sb.AppendLine($"  [{i + 1}] {notes[i]}\n");
     return sb.ToString();
 }

 // ── HTML parsing helpers ───────────────────────────────────────

 static List<(string Title, string Snippet)> ParseSearchResults(string html)
 {
     var results = new List<(string Title, string Snippet)>();

     var titleRegex = new Regex(
         @"<a[^>]+class=""result__a""[^>]*>(.*?)</a>",
         RegexOptions.Singleline);
     var snippetRegex = new Regex(
         @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
         RegexOptions.Singleline);

     var titles = titleRegex.Matches(html);
     var snippets = snippetRegex.Matches(html);

     for (var i = 0; i < titles.Count; i++)
     {
         var title = StripHtml(titles[i].Groups[1].Value).Trim();
         var snippet = i < snippets.Count
             ? StripHtml(snippets[i].Groups[1].Value).Trim()
             : "";

         if (!string.IsNullOrWhiteSpace(title))
             results.Add((title, snippet));
     }

     return results;
 }

 static string StripHtml(string input)
 {
     var text = Regex.Replace(input, @"<[^>]+>", " ");
     text = Regex.Replace(text, @"\s+", " ");
     return System.Net.WebUtility.HtmlDecode(text).Trim();
 }
